import numpy as np
from collections import defaultdict

class NaiveBayesClassifier:
 def __init__(self):
 self.priors = {}
 self.conditionals = {}

 def fit(self, X, y):
 # Calculate prior probabilities
 for label in np.unique(y):
 self.priors[label] = np.mean(y == label)

 # Calculate conditional probabilities
 for feature in range(X.shape[1]):
 for label in np.unique(y):
 self.conditionals[(feature, label)] = np.mean(X[y == label, feature])

 def predict(self, X):
 scores = {}
 for label in self.priors:
 score = self.priors[label]
 for feature in range(X.shape[1]):
 score *= self.conditionals[(feature, label)] ** X[feature]
 scores[label] = score
 return max(scores, key=scores.get)

# Example usage
X = np.array([[1, 1], [1, 0], [0, 1], [0, 0]])
y = np.array([1, 1, 0, 0])

clf = NaiveBayesClassifier()
clf.fit(X, y)
print(clf.predict(np.array([1, 1])))

#include <stdio.h>
#include <stdlib.h>

// Structure to hold prior and conditional probabilities
typedef struct {
 double prior;
 double* conditionals;
} NaiveBayesClassifier;

// Function to calculate prior probabilities
void calculate_priors(NaiveBayesClassifier* clf, int* labels, int n_labels) {
 for (int i = 0; i < n_labels; i++) {
 clf->prior = (double)labels[i] / n_labels;
 }
}

// Function to calculate conditional probabilities
void calculate_conditionals(NaiveBayesClassifier* clf, int** features, int n_features, int n_labels) {
 for (int i = 0; i < n_features; i++) {
 for (int j = 0; j < n_labels; j++) {
 clf->conditionals[i] = (double)features[i][j] / n_labels;
 }
 }
}

// Function to make predictions
int predict(NaiveBayesClassifier* clf, int* features, int n_features) {
 double score = clf->prior;
 for (int i = 0; i < n_features; i++) {
 score *= clf->conditionals[i];
 }
 return score > 0.5;
}

int main() {
 // Example usage
 int labels[] = {1, 1, 0, 0};
 int features[][2] = {{1, 1}, {1, 0}, {0, 1}, {0, 0}};
 NaiveBayesClassifier clf;
 calculate_priors(&clf, labels, 4);
 calculate_conditionals(&clf, features, 2, 4);
 printf("%d\n", predict(&clf, features[0], 2));
 return 0;
}
